insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 0, 'In a partnership, A invests ₹6,000 for 4 months, B ₹4,000 for 6 months, and C ₹8,000 for 3 months. Find the ratio of their profit shares.', 'Partnership में A ₹6,000 को 4 महीने, B ₹4,000 को 6 महीने, और C ₹8,000 को 3 महीने invest करते हैं। profit shares का ratio क्या है?', 'Time-weighted investments: A = 6000 × 4 = 24000; B = 4000 × 6 = 24000; C = 8000 × 3 = 24000. Ratio = 24000 : 24000 : 24000 = 1 : 1 : 1.', 'Three-way partnership profit share uses the product (investment × time) for each partner. Coincidentally equal products give equal shares, which would feel surprising without the calculation.', 'Time-weighted: A = 6000 × 4 = 24000, B = 4000 × 6 = 24000, C = 8000 × 3 = 24000। Ratio = 1 : 1 : 1।', 'तीन-पक्षीय partnership में हर partner का (investment × time) product। Coincidence से equal = equal shares।', 'HARD', array['ratio-proportion','partnership','three-way-time-weighted','cbt1-full-mock','mathematics']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', '1 : 1 : 1', '1 : 1 : 1', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', '6 : 4 : 8', '6 : 4 : 8', false, 'Used only the investment amounts (6:4:8) ignoring durations. Profit depends on investment × time.', 'केवल investments (6:4:8) लगाईं, durations छोड़े। Profit investment × time पर निर्भर।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', '4 : 6 : 3', '4 : 6 : 3', false, 'Used only durations (4:6:3) ignoring investments. Time alone doesn''t determine profit in partnerships.', 'केवल durations (4:6:3) लगाईं, investments छोड़े।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', '2 : 1 : 4', '2 : 1 : 4', false, 'Divided investment by duration (6/4, 4/6, 8/3) → 1.5, 0.67, 2.67 ≈ 2:1:4. Correct is investment × time (not /time).', 'Investment को duration से भाग दिया। सही है investment × time, /time नहीं।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 1, 'A mixture contains milk and water in the ratio 5:1. On adding 5 litres of water, the ratio becomes 5:2. Find the quantity of milk in the mixture originally.', 'एक mixture में दूध और पानी का ratio 5:1 है। 5 litres पानी मिलाने पर ratio 5:2 हो जाता है। मूल mixture में दूध कितना था?', 'Let milk = 5k, water = k. After adding 5L water: milk 5k, water k + 5. New ratio: 5k/(k + 5) = 5/2 ⇒ 2 × 5k = 5(k + 5) ⇒ 10k = 5k + 25 ⇒ k = 5. Milk = 5k = 25 L.', 'Like ratio-12 but with starker asymmetry between milk and water; the same framework (parametrize, update changed side, solve linear) applies. Always distinguish the quantity that changes from the one that stays fixed.', 'Milk = 5k, water = k मानें। 5L water जोड़ने पर milk वही, water k + 5। 5k/(k + 5) = 5/2 ⇒ 10k = 5k + 25 ⇒ k = 5। Milk = 25 L।', 'ratio-12 जैसा framework: changed side पर delta जोड़ें, fixed side k × original रखें, linear equation solve।', 'HARD', array['ratio-proportion','mixture','water-addition','equation-setup','cbt1-full-mock','mathematics']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', '25 litres', '25 litres', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', '30 litres', '30 litres', false, 'Added water 5L to the correct milk 25L: 25 + 5 = 30. Question asks milk alone, not milk + added water.', 'सही milk 25L में पानी 5L जोड़कर 30 दे दिया। Question milk अकेला पूछ रहा है।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', '5 litres', '5 litres', false, 'Reported the quantity of water added (5L) as milk. Confused input with the asked quantity.', 'जोड़े गए पानी (5L) को milk कह दिया।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', '10 litres', '10 litres', false, 'Used k = 2 incorrectly: milk = 5k = 10. Correct k solves 5k/(k + 5) = 5/2 ⇒ k = 5, milk = 25.', 'k = 2 गलत लगाया, milk = 5k = 10। सही 5k/(k + 5) = 5/2 ⇒ k = 5 ⇒ milk = 25।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 2, 'The salaries of A, B, and C are in the ratio 3 : 5 : 7. If their salaries are increased by 50%, 60%, and 50% respectively, find the new ratio of their salaries.', 'A, B, C की salaries का ratio 3 : 5 : 7 है। क्रमशः 50%, 60%, 50% बढ़ोतरी के बाद नया ratio क्या है?', 'New salaries = 3 × 1.5, 5 × 1.6, 7 × 1.5 = 4.5, 8, 10.5. Multiply by 2 to clear decimals: 9, 16, 21. Ratio = 9 : 16 : 21.', 'Different percentage hikes applied to different parts generally change the ratio. Apply each multiplier individually (1.5 for 50%, 1.6 for 60%), then clear decimals by a common factor. Equal hikes preserve the ratio; unequal hikes shift it.', 'नई salaries = 3 × 1.5, 5 × 1.6, 7 × 1.5 = 4.5, 8, 10.5। × 2 से decimals clear: 9, 16, 21। Ratio = 9 : 16 : 21।', 'अलग % hikes से ratio बदलती है। हर multiplier individually लगाएँ (1.5 for 50%, 1.6 for 60%), फिर decimals clear करें।', 'HARD', array['ratio-proportion','percentage-hike','multi-person','cbt1-full-mock','mathematics']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', '9 : 16 : 21', '9 : 16 : 21', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', '3 : 5 : 7', '3 : 5 : 7', false, 'Assumed equal percent hikes preserve the ratio — but B got 60%, the others 50%, so the ratio shifts.', 'Equal hikes होते तो ratio same रहती; B को 60%, बाकी को 50% — ratio बदलेगा।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', '9 : 15 : 21', '9 : 15 : 21', false, 'Scaled all three by 50% (3×1.5, 5×1.5, 7×1.5). B''s hike is 60%, so B → 5 × 1.6 = 8 (in halves: 16 on double-scale), not 15.', 'तीनों को 50% से scale किया (× 1.5)। B पर 60%: 5 × 1.6 = 8 (2x scale पर 16), 15 नहीं।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', '6 : 11 : 14', '6 : 11 : 14', false, 'Doubled the multiplication factor wrong: 3×2, 5×2.2, 7×2. Used factors 2 and 2.2 instead of 1.5 and 1.6.', 'Factors गलत: 1.5/1.6 की जगह 2/2.2 लगा दिए।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 3, 'If the ratio of the sides of two squares is 2:3, find the ratio of their areas.', 'दो squares की sides का ratio 2:3 है। उनके areas का ratio क्या है?', 'Area of a square = side². So area ratio = (side ratio)² = (2/3)² = 4/9.', 'When a linear dimension scales by factor k, area scales by k² and volume by k³. For squares (or any 2D shape), area ratio is always the SQUARE of the linear ratio. Cubes would give k³.', 'Square का area = side²। अतः area ratio = (side ratio)² = (2/3)² = 4/9।', 'Linear dimension k से scale हो तो area k² से, volume k³ से। 2D शapes (square सहित) में area ratio = linear ratio का SQUARE।', 'EASY', array['ratio-proportion','geometric-ratio','area','cbt1-full-mock','mathematics']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', '4 : 9', '4 : 9', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', '2 : 3', '2 : 3', false, 'Reported the side ratio as area ratio. Area scales with the SQUARE of the linear ratio.', 'Side ratio को area ratio मान लिया। Area linear ratio के SQUARE से scale होता है।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', '8 : 27', '8 : 27', false, 'Used side³ (volume scaling, 2³:3³ = 8:27) — that''s the ratio of VOLUMES of CUBES, not areas of squares.', 'Side³ (volume scaling, 2³:3³ = 8:27) लगाया — यह cubes के volumes का ratio है।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', '4 : 6', '4 : 6', false, 'Doubled each side (2×2:3×2 = 4:6 simplifies to 2:3) — linear doubling doesn''t give area.', 'हर side को double किया (2×2:3×2 = 4:6 → 2:3) — linear doubling area नहीं देता।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 4, '₹3,300 is divided among A, B, C, D such that A : B = 1 : 2, B : C = 3 : 5, and C : D = 5 : 7. Find B''s share.', '₹3,300 को A, B, C, D में इस तरह बाँटा गया कि A : B = 1 : 2, B : C = 3 : 5, C : D = 5 : 7। B का share क्या है?', 'Chain: A:B = 1:2; scale by 3 to make B match B:C''s B-part (= 3 → 6), giving A:B = 3:6. So A:B:C = 3:6:10 (B:C scaled to B = 6 ⇒ × 2 ⇒ 6:10). Then C:D = 5:7 → 10:14 (× 2 to make C = 10). Combined: A:B:C:D = 3:6:10:14. Sum = 33. B = 3300 × 6/33 = 600.', 'Chaining three ratios requires iteratively unifying one shared term at a time. Find the LCM of each overlap, scale, advance, and repeat. Missing even one unification step gives an inconsistent chain that under- or over-counts shares.', 'Chain: A:B = 1:2 → 3:6 (× 3 से B = 6 match करे B:C के 3 से ⇒ × 2 करके 6:10); C:D = 5:7 → 10:14 (× 2 से C = 10)। A:B:C:D = 3:6:10:14। Sum = 33। B = 3300 × 6/33 = 600।', 'तीन ratios chain करने के लिए एक-एक shared term को LCM से unify करें। एक भी step छूटा तो chain inconsistent।', 'HARD', array['ratio-proportion','four-way-chained','partition','cbt1-full-mock','mathematics']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', '₹600', '₹600', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', '₹440', '₹440', false, 'Used A:B:C:D = 1:2:5:7 directly without unifying B (2 in first ratio vs 3 in second): sum = 15, B = 3300 × 2/15 = 440. Correct chain unifies B and C via LCM to get 3:6:10:14.', 'A:B:C:D = 1:2:5:7 सीधे लिया (B को unify नहीं किया, 2 vs 3): sum = 15, B = 3300 × 2/15 = 440। सही chain LCM से 3:6:10:14।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', '₹825', '₹825', false, 'Split the total equally among 4 people: 3300/4 = 825. Ratios are unequal; this ignores them.', 'Total को 4 लोगों में बराबर बाँट दिया: 3300/4 = 825। Ratios unequal हैं, यह split उन्हें ignore करता है।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', '₹1,100', '₹1,100', false, 'Divided total by 3 (counted only the 3 stated ratios as splits): 3300/3 = 1100. There are 4 people (A, B, C, D), not 3.', 'Total को 3 से भाग दिया (3 दी हुई ratios को splits मान लिया): 3300/3 = 1100। People 4 हैं (A, B, C, D), 3 नहीं।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 5, 'Find the average of 12, 18, 24, 30, 36.', '12, 18, 24, 30, 36 का average निकालिए।', 'Sum = 12 + 18 + 24 + 30 + 36 = 120. Count = 5. Average = 120/5 = 24.', 'Average (arithmetic mean) = sum of values / count of values. For an arithmetic progression (equal step between successive terms), the mean equals the middle term — handy shortcut here: middle = 24. The longer route via sum/count gives the same answer; both are useful sanity checks.', 'Sum = 12 + 18 + 24 + 30 + 36 = 120। Count = 5। Average = 120/5 = 24।', 'Average (arithmetic mean) = sum / count। AP (equal step) के लिए mean = middle term — यहाँ middle = 24, shortcut।', 'EASY', array['average','basic','cbt1-full-mock','mathematics']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', '24', '24', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', '120', '120', false, 'Reported the SUM (12+18+24+30+36 = 120) as the average. Average = sum / count, not sum alone.', 'SUM (12+18+24+30+36 = 120) को average दे दिया। Average = sum / count होता है।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', '20', '20', false, 'Divided sum 120 by 6 (miscounted as 6 numbers): 120/6 = 20. There are 5 numbers, not 6.', 'Sum 120 को 6 से भाग दिया (6 numbers मान लिए): 120/6 = 20। यहाँ 5 numbers हैं, 6 नहीं।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', '30', '30', false, 'Used the median (middle value of the sorted list = 24 — wait, median is 24, same as average for an AP). 30 came from picking the 4th value rather than computing.', 'Sorted list की median (= 24) के बजाय 4-th value 30 ली। Average computation नहीं किया।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 6, 'The average of 5 numbers is 28. If one number is excluded, the average becomes 26. Find the excluded number.', '5 संख्याओं का average 28 है। एक संख्या हटाने पर average 26 हो जाता है। हटाई गई संख्या क्या है?', 'Original sum = 5 × 28 = 140. New sum = 4 × 26 = 104. Excluded = 140 − 104 = 36.', 'When a number is excluded from a set, the change in total sum equals exactly that excluded number. Compute (old count × old avg) − (new count × new avg) = excluded value.', 'Original sum = 5 × 28 = 140। New sum = 4 × 26 = 104। Excluded = 140 − 104 = 36।', 'Set से एक number हटाने पर sum में जो change होता है वही excluded value है। (पुरानी count × पुरानी avg) − (नई count × नई avg) = excluded।', 'EASY', array['average','exclusion','sum-shift','cbt1-full-mock','mathematics']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', '36', '36', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', '26', '26', false, 'Reported the new average (26) as the excluded number. The excluded number is total sum (140) minus remaining sum (4 × 26 = 104) = 36.', 'नई average (26) को excluded number कह दिया। Excluded = total sum (140) − शेष sum (4 × 26 = 104) = 36।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', '2', '2', false, 'Subtracted the two averages: 28 − 26 = 2. The excluded number isn''t the difference of averages; it''s old sum minus new sum.', 'दोनों averages घटाए: 28 − 26 = 2। Excluded number averages का difference नहीं — यह old sum − new sum है।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', '30', '30', false, 'Computed 5 × 28 − 4 × 26 = 140 − 104 = 36 correctly but reported 30 (arithmetic slip — 140 − 110 = 30).', '5 × 28 = 140 सही, पर 4 × 26 को 110 लिखा (4 × 26 = 104 सही): 140 − 110 = 30।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 7, 'Find the average of the first 10 natural numbers.', 'पहले 10 प्राकृत संख्याओं का average निकालिए।', 'Average of first n natural numbers = (n+1)/2 = 11/2 = 5.5.', 'First n natural numbers (1, 2, ..., n) form an arithmetic progression with first term 1 and last term n. The average of an AP is the average of first and last terms: (1 + n)/2 = (n+1)/2. For n = 10: 11/2 = 5.5.', 'पहले n natural numbers का average = (n+1)/2 = 11/2 = 5.5।', 'पहले n natural numbers AP बनाते हैं (first = 1, last = n)। AP का average = (first + last)/2 = (1 + n)/2 = (n+1)/2।', 'EASY', array['average','natural-numbers','consecutive','cbt1-full-mock','mathematics']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', '5.5', '5.5', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', '5', '5', false, 'Computed (n+1)/2 = 11/2 = 5.5 but truncated the decimal: 5.5 → 5. Average is exactly 5.5.', '(n+1)/2 = 5.5 निकाला पर decimal truncate करके 5 दिया।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', '55', '55', false, 'Reported the SUM (1+2+...+10 = 55) as the average. Average = sum/n = 55/10 = 5.5.', 'Sum (1+2+...+10 = 55) को average दे दिया। Average = sum/n = 5.5।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', '6', '6', false, 'Used n/2 = 10/2 = 5, then added 1: got 6. The formula for first-n-naturals average is (n+1)/2, not n/2 + 1.', 'n/2 = 5, फिर + 1 = 6 किया। सही formula (n+1)/2 है।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 8, 'The average of 6 consecutive even numbers is 25. Find the largest of these numbers.', '6 लगातार सम (even) संख्याओं का average 25 है। इनमें सबसे बड़ी संख्या क्या है?', '6 consecutive evens have a span of 10 (5 gaps of 2). Average sits at the centre; largest = avg + (n−1)/2 × step = 25 + 5 × 1 = wait, the gap from middle of 6-term AP to last term = 2.5 × 2 = 5. So largest = 25 + 5 = 30.', 'For an AP of n terms with common difference d and average A, the largest = A + ((n−1)/2) × d. With n = 6, d = 2: largest = A + 2.5 × 2 = A + 5. The average is between the two middle terms (24 and 26), not equal to any specific term.', '6 consecutive evens का span 10 (5 gaps × 2)। Average centre पर है। Largest = avg + ((n−1)/2) × d = 25 + 2.5 × 2 = 30।', 'AP में n terms, common difference d, average A हो तो largest = A + ((n−1)/2) × d। यहाँ n = 6, d = 2, largest = 25 + 5 = 30।', 'EASY', array['average','consecutive-even','ap','cbt1-full-mock','mathematics']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', '30', '30', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', '20', '20', false, 'Reported the SMALLEST even number (avg − 5 = 20) instead of the largest. Largest = avg + 5 = 30.', 'सबसे छोटी (avg − 5 = 20) दे दी, सबसे बड़ी नहीं। Largest = avg + 5 = 30।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', '25', '25', false, 'Reported the average itself as the largest. The average of even consecutive numbers is between two of them (here, 24 and 26), not equal to any.', 'Average को ही largest दे दिया। Even consecutive का average दो terms (24 और 26) के बीच होता है, किसी एक के बराबर नहीं।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', '28', '28', false, 'Used the 5th term: with average 25 between 24 and 26, the numbers are 20, 22, 24, 26, 28, 30. Picked the 5th (28) instead of the 6th (30).', '5वीं term (28) दे दी। Numbers हैं: 20, 22, 24, 26, 28, 30। Largest 6वीं term = 30।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 9, 'The average of 4 numbers is 25. If a fifth number is included and the new average is 27, find the fifth number.', '4 संख्याओं का average 25 है। पाँचवीं संख्या जोड़ने पर नया average 27 हो गया। पाँचवीं संख्या क्या है?', 'Old sum = 4 × 25 = 100. New sum = 5 × 27 = 135. Fifth number = 135 − 100 = 35.', 'Adding a new number to a set shifts the sum by exactly that number''s value. Compute (new count × new avg) − (old count × old avg) = added value. The shortcut formula (avg shift × new count) + old avg also works but is more error-prone.', 'पुराना sum = 4 × 25 = 100। नया sum = 5 × 27 = 135। पाँचवीं संख्या = 135 − 100 = 35।', 'Set में नई संख्या जोड़ने पर sum उतना ही बदलता है। (नई count × नई avg) − (पुरानी count × पुरानी avg) = added value।', 'EASY', array['average','addition','sum-shift','cbt1-full-mock','mathematics']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', '35', '35', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', '27', '27', false, 'Reported the new average (27) as the fifth number. New value = new total − old total = 5×27 − 4×25 = 135 − 100 = 35.', 'नई average (27) को पाँचवीं संख्या मान लिया। सही: 5×27 − 4×25 = 135 − 100 = 35।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', '2', '2', false, 'Subtracted the two averages: 27 − 25 = 2. The fifth number isn''t the average difference; it''s the difference of total sums.', 'दोनों averages घटाए: 27 − 25 = 2। पाँचवीं संख्या total sums का difference है, averages का नहीं।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', '10', '10', false, 'Computed 5 × 27 − 4 × 25 = 135 − 100 but wrote 100 − 90 = 10 (slipped 4 × 25 to 90 instead of 100).', '5 × 27 = 135 सही, पर 4 × 25 को 90 (= 4 × 22.5 जैसा slip) मानकर 135 − 100 की जगह 100 − 90 = 10 लिख दिया।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 10, 'The average of 8 numbers is 21. The average of the first 5 is 19 and that of the last 4 is 24. Find the 5th number.', '8 संख्याओं का average 21 है। पहले 5 का average 19 और अंतिम 4 का average 24 है। 5वीं संख्या क्या है?', 'Sum of all 8 = 8 × 21 = 168. Sum of first 5 = 5 × 19 = 95. Sum of last 4 = 4 × 24 = 96. The 5th number is counted in both the first-5 and the last-4 (since first-5 + last-4 = 9 entries but only 8 distinct, the overlap is the 5th). 95 + 96 = 191; subtract total 168: 5th = 191 − 168 = 23.', 'When two groups overlap on one element, the sum of group sums counts the overlapping element twice. So the overlap = (sum of group sums) − (total sum). This ''inclusion–exclusion'' for sums isolates the shared element.', 'कुल sum = 8 × 21 = 168। पहले 5 का sum = 5 × 19 = 95। अंतिम 4 का sum = 4 × 24 = 96। दोनों groups में 5वीं संख्या double-count हुई: 95 + 96 = 191, 5वीं = 191 − 168 = 23।', 'जब दो groups में एक element overlap करता है, तो group sums का sum उस element को दो बार count करता है। अतः overlap = (group sums का sum) − (total sum)।', 'MEDIUM', array['average','overlap','shared-element','cbt1-full-mock','mathematics']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', '23', '23', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', '21', '21', false, 'Reported the overall average (21) as the 5th number. The 5th number is shared between the first-5 and last-4 groups; its specific value comes from sum-overlap reasoning.', 'Overall average (21) को 5वीं संख्या कह दिया। 5वीं संख्या first-5 और last-4 दोनों में है — overlap-sum logic से निकलती है।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', '24', '24', false, 'Reported the last-4 average (24) as the 5th number. The 5th is in the first-5 group, not the last-4.', 'Last-4 average (24) को 5वीं कह दिया। 5वीं संख्या first-5 में है, last-4 में नहीं।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', '19', '19', false, 'Reported the first-5 average (19) as the 5th number. The first-5 average is the average of those 5, not the 5th specifically.', 'First-5 average (19) को 5वीं कह दिया। यह उन 5 का average है, specifically 5वीं नहीं।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 11, 'The average weight of 50 students in a class is 50 kg. The average weight of the first 25 is 48 kg, and that of the last 24 is 52 kg. Find the weight of the 26th student.', '50 छात्रों का average weight 50 kg है। पहले 25 का average 48 kg और अंतिम 24 का 52 kg है। 26वें छात्र का weight क्या है?', 'Total sum = 50 × 50 = 2500. First-25 sum = 25 × 48 = 1200. Last-24 sum = 24 × 52 = 1248. Covered sum = 1200 + 1248 = 2448. These groups cover students 1-25 and 27-50, so student 26 is missing. Weight of the 26th student = 2500 − 2448 = 52 kg.', 'When two non-overlapping groups leave one student outside both groups, add the group sums and subtract from the total class sum. Here first 25 plus last 24 covers 49 students; the omitted 26th student''s weight is 52 kg.', 'Total sum = 50 × 50 = 2500। First-25 sum = 25 × 48 = 1200। Last-24 sum = 24 × 52 = 1248। Covered sum = 1200 + 1248 = 2448। ये groups students 1-25 और 27-50 को cover करते हैं, इसलिए 26वाँ छात्र missing है। 26वें छात्र का weight = 2500 − 2448 = 52 kg।', 'जब दो non-overlapping groups एक छात्र को बाहर छोड़ दें, तो group sums जोड़कर total class sum से घटाएँ। यहाँ first 25 + last 24 = 49 छात्र cover होते हैं; omitted 26वें छात्र का weight 52 kg है।', 'MEDIUM', array['average','overlap','weight-problem','cbt1-full-mock','mathematics']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', '52 kg', '52 kg', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', '50 kg', '50 kg', false, 'Reported the overall average (50) as the 26th student''s weight. The 26th is omitted by the two groups; compute total sum minus covered sums.', 'Overall average (50) को 26वें का weight मान लिया। 26वाँ दोनों groups से omitted है; total sum − covered sums करें।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', '48 kg', '48 kg', false, 'Reported the first-25 average (48) as the 26th student''s weight. The 26th is not in the first-25 group; use the missing-student sum gap.', 'First-25 average (48) को 26वें का weight मान लिया। 26वाँ first-25 group में नहीं है; missing-student sum gap निकालें।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', '100 kg', '100 kg', false, 'Doubled the overall average (50 × 2 = 100) instead of subtracting covered sums from total. There is no doubling step in this method.', 'Overall average को double करके 50 × 2 = 100 कर दिया। इस method में doubling step नहीं है; total से covered sums घटते हैं।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 12, 'The average age of 5 friends is 30 years. After 5 years, what will be their average age?', '5 दोस्तों की average age 30 साल है। 5 साल बाद उनकी average age क्या होगी?', 'When every value rises by the same amount d, the average rises by d. New avg = 30 + 5 = 35.', 'Average is a linear operation: shifting every input by a constant shifts the output by the same constant. Useful sanity check: ages all rise by 5, so the average rises by 5 — no need to recompute the sum.', 'जब हर value में same amount d जुड़े, तो average भी d बढ़ता है। नई avg = 30 + 5 = 35।', 'Average linear operation है: हर input में constant जोड़ने पर output में वही constant जुड़ता है। हर age 5 बढ़ी ⇒ average 5 बढ़ी।', 'EASY', array['average','age','uniform-shift','cbt1-full-mock','mathematics']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', '35 years', '35 साल', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', '30 years', '30 साल', false, 'Kept the average unchanged. Adding the same amount (5 years) to every value shifts the average by exactly that amount.', 'Average वही रखी। हर value में same amount जोड़ने पर average भी उतना ही बढ़ता है।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', '31 years', '31 साल', false, 'Divided the 5-year shift by 5 (people): 30 + 5/5 = 31. The shift applies to every person, not the group sum once.', '5-year shift को 5 (लोग) से भाग दिया: 30 + 5/5 = 31। Shift हर person पर लगता है, group sum पर एक बार नहीं।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', '34 years', '34 साल', false, 'Added 4 instead of 5 (slipped a year): 30 + 4 = 34. The question states 5 years exactly.', '5 की जगह 4 जोड़ दिया (एक साल slip): 30 + 4 = 34। Question में 5 साल है।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 13, 'The average of three numbers is 20. The first and second numbers are equal, and the third is 26. Find the first number.', 'तीन संख्याओं का average 20 है। पहली और दूसरी संख्याएँ बराबर हैं और तीसरी 26 है। पहली संख्या क्या है?', 'Sum = 3 × 20 = 60. Let first = second = x. Then 2x + 26 = 60 ⇒ 2x = 34 ⇒ x = 17.', 'When several values share a common unknown, parametrize and use the average-defined sum to set up one equation. With one shared unknown across two of the three slots, the equation is linear in that unknown.', 'Sum = 3 × 20 = 60। पहली = दूसरी = x मानें। 2x + 26 = 60 ⇒ 2x = 34 ⇒ x = 17।', 'जब कई values एक common unknown share करें, उस unknown से parametrize करें और average से sum निकालकर equation बनाएँ। यहाँ एक linear equation।', 'MEDIUM', array['average','equation-setup','equal-pair','cbt1-full-mock','mathematics']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', '17', '17', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', '20', '20', false, 'Reported the average (20) as the first number. The third (26) is above average, so the first two must be below to balance.', 'Average (20) को पहली संख्या कह दिया। तीसरी (26) average से ऊपर है — पहली दो को नीचे होना चाहिए।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', '13', '13', false, 'Used 60 − 26 − 26 = 8 (treated third as ''doubled'' through some confusion) − no clear path. Set 2x + 26 = 60 ⇒ 2x = 34 ⇒ x = 17.', 'Algebra गलत: 2x + 26 = 60 ⇒ 2x = 34 ⇒ x = 17। यहाँ 13 के लिए 2x = 26 लगा बैठे।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', '14', '14', false, 'Computed (60 − 26)/2 incorrectly: divided 28 (not 34) by 2. The numerator is 60 − 26 = 34, not 28.', '(60 − 26)/2 गलत: 28/2 = 14 लगाया। सही numerator 34 है: 34/2 = 17।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 14, 'A batsman in his 17th innings makes a score of 85, thereby increasing his average by 3 runs. Find his average after the 17th innings.', 'एक batsman 17वीं innings में 85 बनाता है, जिससे उसका average 3 runs बढ़ जाता है। 17वीं innings के बाद उसका average क्या है?', 'Let new avg = x. Then old avg = x − 3. Sum after 17 innings = 17x; sum after 16 = 16(x − 3). Score in 17th = 17x − 16(x−3) = x + 48. Set x + 48 = 85 ⇒ x = 37.', 'An innings score equals the new total minus the old total. The new total is (count_new × avg_new); the old is (count_old × avg_old). When the average shifts by Δ across a single new entry, the entry value = new_avg + (count_new − 1) × Δ. Here: 37 + 16 × 3 = 85 ✓.', 'नया avg = x मानें। पुराना = x − 3। 17 innings का sum = 17x; 16 का = 16(x − 3)। 17वीं का score = 17x − 16(x−3) = x + 48 = 85 ⇒ x = 37।', 'एक innings का score = नया total − पुराना total। नया = count × new_avg; पुराना = (count−1) × old_avg। Shortcut: score = new_avg + (count_new − 1) × Δ। यहाँ 37 + 16 × 3 = 85 ✓।', 'MEDIUM', array['average','cricket','average-shift','cbt1-full-mock','mathematics']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', '37', '37', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', '40', '40', false, 'Used new-average formula but added 3 to 37, getting 40. The shift is FROM old to new; new = old + 3 = 34 + 3 = 37, not 40.', 'Shift को 3 की जगह 6 लगा दिया: 34 + 6 = 40। सही new = old + 3 = 37।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', '85', '85', false, 'Reported the score in the 17th innings (85) as the average. The score is the input; the average is the output.', '17वीं innings का score (85) को average कह दिया। Score input है, average output।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', '34', '34', false, 'Reported the OLD average (34) instead of the new. New average = old + 3 = 37 (after the 85-run innings).', 'OLD average (34) को नया कह दिया। नया = old + 3 = 37।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 15, 'The average of 7 consecutive odd numbers is 25. Find the largest of them.', '7 लगातार विषम संख्याओं का average 25 है। उनमें सबसे बड़ी कौन-सी है?', '7 consecutive odd numbers form an AP with d = 2. Middle (4th) = average = 25. Numbers: 19, 21, 23, 25, 27, 29, 31. Largest = 31.', 'An AP with an ODD number of terms has its middle term equal to the average. With n = 7 and d = 2, the largest = middle + 3d = 25 + 6 = 31. The same logic gives smallest = middle − 3d = 19.', '7 consecutive odd numbers AP बनाते हैं (d = 2)। Middle (4th) = average = 25। Numbers: 19, 21, 23, 25, 27, 29, 31। Largest = 31।', 'Odd-count AP में middle term = average। n = 7, d = 2 हो तो largest = middle + 3d = 25 + 6 = 31; smallest = middle − 3d = 19।', 'MEDIUM', array['average','consecutive-odd','ap','cbt1-full-mock','mathematics']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', '31', '31', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', '25', '25', false, 'Reported the average (25) as the largest. With odd terms count = 7, the average IS the middle term, but the largest is the 7th, not the 4th.', 'Average (25) को largest कह दिया। 7 terms (odd count) में average = middle term (4th); largest = 7वीं term।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', '27', '27', false, 'Used the 5th term (one above middle): 25 + 2 = 27. Largest = 7th term = 25 + 6 = 31.', '5वीं term (middle + 2 = 27) को largest कह दिया। 7वीं term = 25 + 6 = 31।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', '19', '19', false, 'Reported the SMALLEST (avg − 6 = 19) instead of the largest. Numbers are 19, 21, 23, 25, 27, 29, 31.', 'Smallest (avg − 6 = 19) को largest कह दिया। Numbers: 19, 21, 23, 25, 27, 29, 31।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 16, 'In a class of 50 students, 30 are boys whose average weight is 60 kg, and the rest are girls whose average weight is 50 kg. Find the average weight of the entire class.', '50 छात्रों की class में 30 लड़के हैं (average weight 60 kg) और बाकी लड़कियाँ (average weight 50 kg)। पूरी class का average weight क्या है?', 'Total weight = 30 × 60 + 20 × 50 = 1800 + 1000 = 2800 kg. Avg = 2800/50 = 56 kg.', 'Combined average for two groups = (n₁ × avg₁ + n₂ × avg₂) / (n₁ + n₂). The group sizes are the weights — bigger group pulls the combined average closer to its own average. Plain arithmetic mean of the two averages is wrong unless the groups are equal-sized.', 'Total weight = 30 × 60 + 20 × 50 = 1800 + 1000 = 2800 kg। Avg = 2800/50 = 56 kg।', 'दो groups का combined average = (n₁ × avg₁ + n₂ × avg₂) / (n₁ + n₂)। Group sizes weights हैं — बड़ा group combined avg को अपनी ओर खींचता है।', 'MEDIUM', array['average','weighted-average','two-groups','cbt1-full-mock','mathematics']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', '56 kg', '56 kg', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', '55 kg', '55 kg', false, 'Used arithmetic mean of the two group averages: (60 + 50)/2 = 55. Plain average ignores group sizes (30 boys vs 20 girls).', 'दोनों averages का arithmetic mean: (60 + 50)/2 = 55। Group sizes (30 vs 20) ignore हो गए।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', '58 kg', '58 kg', false, 'Approximated to ''closer to boys'' average'' (60) by midway-up: 55 + 3 = 58. Correct weighted: (30×60 + 20×50)/50 = 56.', 'Boys-side bias मानकर 55 + 3 = 58 लगाया। सही weighted: (30×60 + 20×50)/50 = 56।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', '60 kg', '60 kg', false, 'Reported the boys-only average (60) as the class average. That ignores the 20 girls entirely.', 'Boys का average (60) ही class का दे दिया। 20 लड़कियाँ ignore हुईं।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 17, 'The average of 11 numbers is 22. The average of the first 6 numbers is 19, and the average of the last 6 is 27. Find the 6th number.', '11 संख्याओं का average 22 है। पहले 6 का average 19 और अंतिम 6 का 27 है। 6वीं संख्या क्या है?', 'Sum of all 11 = 11 × 22 = 242. First-6 sum = 6 × 19 = 114. Last-6 sum = 6 × 27 = 162. Sum of group sums = 114 + 162 = 276. The 6th number is in both groups (since 6 + 6 = 12 > 11, exactly one overlap), so 6th = 276 − 242 = 34.', 'When two same-size groups (6 + 6 = 12) cover 11 distinct items, exactly one item is shared. The shared item''s value = (group sums sum) − (total sum) by inclusion–exclusion on sums.', 'Total sum = 242, first-6 sum = 114, last-6 sum = 162। 6 + 6 = 12 > 11 ⇒ एक overlap। 6वीं = 114 + 162 − 242 = 34।', 'जब दो groups (6 + 6 = 12) 11 distinct items cover करें, एक item shared है। उसका value = (group sums का sum) − (total sum)।', 'MEDIUM', array['average','overlap','shared-element','cbt1-full-mock','mathematics']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', '34', '34', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', '22', '22', false, 'Reported the overall average (22) as the 6th number. The 6th is the unique overlap; compute via group sums.', 'Overall average (22) को 6वीं संख्या कह दिया। 6वीं unique overlap है — group sums से निकलेगी।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', '24', '24', false, 'Halved the difference (27 + 19)/2 = 23, then nudged up to 24. Correct: 6th = (6×19 + 6×27) − 11×22 = 114 + 162 − 242 = 34.', '(27 + 19)/2 = 23, फिर 24 कर दिया। सही: 6th = 6×19 + 6×27 − 11×22 = 114 + 162 − 242 = 34।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', '8', '8', false, 'Subtracted the wrong direction: (6 × 22) − (6 × 19) = 18, off by some slip to 8. Correct path: sum-of-group-sums minus total.', 'गलत direction में घटाया। सही: (group sums का sum) − total = 276 − 242 = 34।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 18, 'The average of 5 consecutive integers starting from m is n. What is the value of n?', 'm से शुरू होने वाले 5 लगातार integers का average n है। n का मान क्या है?', '5 consecutive integers m, m+1, m+2, m+3, m+4. Sum = 5m + 10. Avg = m + 2.', 'For an odd-count AP with first term m and common difference 1, the average equals the middle term, which is m + (count−1)/2. With count = 5, offset = 2, so avg = m + 2.', '5 consecutive integers m, m+1, m+2, m+3, m+4। Sum = 5m + 10। Avg = m + 2।', 'Odd-count AP (first = m, d = 1) में average = middle term = m + (count−1)/2। count = 5 ⇒ offset = 2 ⇒ avg = m + 2।', 'MEDIUM', array['average','consecutive','algebra','cbt1-full-mock','mathematics']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', 'm + 2', 'm + 2', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', 'm', 'm', false, 'Reported m (the smallest) as the average. For 5 consecutive integers m to m+4, the average is the middle = m+2.', 'm (smallest) को average कह दिया। 5 consecutive integers (m से m+4 तक) का average middle = m + 2।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', 'm + 4', 'm + 4', false, 'Reported m+4 (the largest) as the average. The average is the middle term, not the largest.', 'm + 4 (largest) को average कह दिया। Average middle term है, largest नहीं।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', 'm + 2.5', 'm + 2.5', false, 'Used (n−1)/2 with n = 6 (one too many): (6−1)/2 = 2.5, giving m + 2.5. With 5 numbers, the offset is (5−1)/2 = 2, not 2.5.', 'n = 6 ले लिया (एक ज़्यादा): (6−1)/2 = 2.5 ⇒ m + 2.5। यहाँ n = 5 ⇒ offset = (5−1)/2 = 2।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 19, 'A man purchases two articles for ₹600 and ₹900 with profit percentages of 20% and 10% respectively. Find his overall profit percentage.', 'एक व्यक्ति दो articles ₹600 और ₹900 में खरीदकर क्रमशः 20% और 10% profit पर बेचता है। overall profit% क्या है?', 'Profits: 20% of 600 = 120; 10% of 900 = 90. Total profit = 210. Total cost = 1500. Overall profit% = 210/1500 × 100 = 14%.', 'When profit percents are applied to different cost bases, the OVERALL profit% is the weighted average — weights are the COST values (not the SP values, not the count of items). Equivalently, sum the absolute profits and divide by total cost.', 'Profits: 600 का 20% = 120; 900 का 10% = 90। Total profit = 210। Total cost = 1500। Overall profit% = 210/1500 × 100 = 14%।', 'अलग cost bases पर profit percents में overall = COST values से weighted average (count या SP नहीं)। Absolute profits जोड़कर total cost से भाग दें।', 'MEDIUM', array['average','weighted-percentage','profit-loss','cbt1-full-mock','mathematics']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', '14%', '14%', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', '15%', '15%', false, 'Used arithmetic mean of percentages: (20 + 10)/2 = 15%. Different costs require WEIGHTED average by cost size.', 'Percentages का arithmetic mean: (20 + 10)/2 = 15%। अलग costs में WEIGHTED average चाहिए।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', '12%', '12%', false, 'Reported 600/900 × something giving 12%. Correct: total profit = 120 + 90 = 210; total cost = 1500; 210/1500 = 14%.', 'Random arithmetic से 12% लगाया। सही: total profit = 120 + 90 = 210, total cost = 1500, 210/1500 = 14%।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', '16%', '16%', false, 'Used wrong weights: weighted by 900 (larger) instead of by both. (20 × 600 + 10 × 900)/1000 hands a wrong divisor → 21%. 16% comes from a similar arithmetic slip.', 'Wrong weights: divisor 1000 लिया (1500 की जगह), या weights swap किए। सही: profit weight cost से, total cost 1500।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 20, 'The average of 10 numbers is 15. If each number is multiplied by 4, what will be the new average?', '10 संख्याओं का average 15 है। हर संख्या को 4 से गुणा करने पर नया average क्या होगा?', 'Multiplying every value by 4 multiplies the average by 4: new avg = 15 × 4 = 60.', 'Average is a linear operation: scaling every input by k scales the output by k (likewise additive shifts). New avg = k × old avg.', 'हर value को 4 से गुणा करने पर average भी 4 गुना: नई avg = 15 × 4 = 60।', 'Average linear operation है: हर input को k से scale करने पर output भी k गुना। नई avg = k × पुरानी avg।', 'EASY', array['average','uniform-scale','multiplication','cbt1-full-mock','mathematics']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', '60', '60', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', '15', '15', false, 'Kept the average unchanged. Multiplying every value by k multiplies the average by k.', 'Average वही रखी। हर value को k से गुणा करने पर average भी k गुना हो जाता है।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', '19', '19', false, 'Added 4 to the average: 15 + 4 = 19. Multiplying by k is NOT the same as adding k to the average.', 'Average में 4 जोड़ दिया: 15 + 4 = 19। Multiply by k और add k अलग operations हैं।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', '150', '150', false, 'Multiplied by 10 instead of 4 (used count instead of multiplier): 15 × 10 = 150. The multiplier is 4.', '4 की जगह 10 (count) से गुणा कर दिया: 15 × 10 = 150। Multiplier 4 है।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 21, 'The average marks of 39 students in a class is 64. The class teacher''s marks are also added, raising the average by 1. Find the teacher''s marks.', 'एक कक्षा के 39 छात्रों का औसत marks 64 है। शिक्षक के marks जोड़ने पर औसत 1 बढ़ जाता है। शिक्षक के marks क्या हैं?', 'Old sum = 39 × 64 = 2496. New sum = 40 × 65 = 2600. Teacher''s marks = 2600 − 2496 = 104. Shortcut: teacher = new_avg + (count_new − 1) × Δ = 65 + 39 × 1 = 104.', 'Inclusion of a new entry that shifts the average by Δ has the entry value equal to (new_avg) + (count_new − 1) × Δ. Equivalently: the new entry must contribute Δ to its own average AND lift everyone else by Δ.', 'Old sum = 39 × 64 = 2496। New sum = 40 × 65 = 2600। Teacher = 2600 − 2496 = 104। Shortcut: new_avg + (count_new − 1) × Δ = 65 + 39 = 104।', 'नया entry जोड़ने से average Δ बढ़े, तो उसकी value = new_avg + (count_new − 1) × Δ। यह entry खुद को नई average तक उठाता है AND बाकी सब को भी Δ ऊपर ले जाता है।', 'MEDIUM', array['average','addition','inclusion-shift','cbt1-full-mock','mathematics']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', '104', '104', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', '65', '65', false, 'Reported the new average (65) as the teacher''s marks. The teacher''s marks must be high enough to raise the average; specifically, new_avg + (count_new − 1) × Δ = 65 + 39 × 1 = 104.', 'नई average (65) को शिक्षक के marks कह दिया। Shortcut: new_avg + (count_new − 1) × Δ = 65 + 39 = 104।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', '40', '40', false, 'Used 40 × 1 = 40 (treated count as a multiplicative answer). Correct: teacher = 40 × 65 − 39 × 64 = 2600 − 2496 = 104.', '40 × 1 = 40 लगाया (count को answer मान लिया)। सही: teacher = 40 × 65 − 39 × 64 = 104।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', '1', '1', false, 'Reported the average shift Δ = 1 as the teacher''s marks. The shift moves the entire group; the marks that produce that shift are much larger.', 'Average shift Δ = 1 को शिक्षक के marks दे दिया। Shift पूरे group पर लगता है; उसे cause करने वाले marks बहुत बड़े होते हैं।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 22, 'The average of three numbers is 40. The first is twice the second, and the third is 3 times the first. Find the numbers.', 'तीन संख्याओं का average 40 है। पहली, दूसरी की दोगुनी है और तीसरी, पहली की 3 गुनी है। संख्याएँ क्या हैं?', 'Let second = x. First = 2x, third = 3 × first = 6x. Sum = 2x + x + 6x = 9x. Average = 9x/3 = 3x = 40 ⇒ x = 40/3 ≈ 13.33. So numbers are 26.67, 13.33, 80.', 'Translate ratio statements into algebra by parametrizing. Each subsequent value depends on the first; substitute and simplify until you have one equation in one unknown. The fact that the answer is non-integer is fine — averages don''t require integers.', 'दूसरी = x मानें। पहली = 2x, तीसरी = 3 × first = 6x। Sum = 9x। Average = 9x/3 = 3x = 40 ⇒ x = 40/3 ≈ 13.33। संख्याएँ: 26.67, 13.33, 80।', 'Ratio statements को algebra में translate करें। एक unknown में एक equation बनाएँ। Non-integer answer OK — averages integer demand नहीं करते।', 'HARD', array['average','algebra','ratio-relations','cbt1-full-mock','mathematics']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', '24, 12, 72', '24, 12, 72', false, 'Sum = 108; avg = 36, not 40. Used wrong scale x = 12 (giving sum 9x = 108).', 'Sum = 108; avg = 36, 40 नहीं। Wrong scale x = 12।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', '26.67, 13.33, 80', '26.67, 13.33, 80', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', '20, 10, 60', '20, 10, 60', false, 'Sum = 90, avg = 30 (not 40). Used scale 10 instead of 13.33.', 'Sum = 90, avg = 30 (40 नहीं)। Scale 10 लगाया, 13.33 नहीं।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', '30, 15, 90', '30, 15, 90', false, 'Sum = 135, avg = 45 (not 40). Scale 15.', 'Sum = 135, avg = 45 (40 नहीं)। Scale 15।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 23, 'A train covers 60 km at 30 km/h, 60 km at 60 km/h, and 60 km at 20 km/h. Find its average speed for the entire journey.', 'एक train 60 km को 30 km/h पर, 60 km को 60 km/h पर, और 60 km को 20 km/h पर तय करती है। पूरी यात्रा की average speed क्या है?', 'Total distance = 180 km. Time = 60/30 + 60/60 + 60/20 = 2 + 1 + 3 = 6 h. Avg speed = 180/6 = 30 km/h.', 'Average speed for equal-distance legs is the harmonic mean of leg speeds: 3/(1/30 + 1/60 + 1/20) = 3/(2/60 + 1/60 + 3/60) = 3 × 60/6 = 30. Compute by total-distance/total-time directly to avoid harmonic-mean formula errors.', 'Total distance = 180 km। Time = 60/30 + 60/60 + 60/20 = 2 + 1 + 3 = 6 h। Avg speed = 180/6 = 30 km/h।', 'Equal-distance legs पर average speed = harmonic mean। सीधे total-distance/total-time से निकालें — formula error से बचेंगे।', 'MEDIUM', array['average','average-speed','harmonic-mean','cbt1-full-mock','mathematics']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', '30 km/h', '30 km/h', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', '36.67 km/h', '36.67 km/h', false, 'Used arithmetic mean: (30 + 60 + 20)/3 = 110/3 = 36.67. Equal-distance legs need HARMONIC mean, not arithmetic.', 'Arithmetic mean: (30 + 60 + 20)/3 = 110/3 = 36.67। Equal-distance legs में HARMONIC mean चाहिए।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', '33.33 km/h', '33.33 km/h', false, 'Used 100/3 = 33.33 as some ''midway'' value. Correct: total distance 180 / total time 6 = 30.', '100/3 = 33.33 को midway value मान लिया। सही: total distance 180 / total time 6 = 30।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', '40 km/h', '40 km/h', false, 'Used (30 + 60)/2 = 45, then (45 + 20)/2 = 32.5, snapped to 40. Step-by-step pairwise averaging is wrong; compute one harmonic mean over all three.', 'Stepwise pairwise average: (30+60)/2 = 45, फिर (45+20)/2 = 32.5 → 40 लगाया। एक ही harmonic mean तीनों पर लगती है।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 24, 'The average age of a husband and wife at the time of their marriage was 22 years. 5 years after marriage they have a 3-year-old child. Find the present average age of the family.', 'पति-पत्नी की शादी के समय average age 22 साल थी। शादी के 5 साल बाद उनका 3 साल का बच्चा है। परिवार की वर्तमान average age क्या है?', 'Sum of spouses at marriage = 22 × 2 = 44. After 5 years, spouses'' sum = 44 + 5 × 2 = 54. Add child (3 years): family sum = 57. Family of 3 ⇒ avg = 57/3 = 19 years.', 'When the time elapsed shifts every existing member''s age by the same amount, the SUM increases by (members × elapsed). Adding a new member adds their age to the sum but increases the count by 1, so the average dilutes. Compute new sum and divide by new count.', 'शादी पर spouses की sum = 22 × 2 = 44। 5 साल बाद spouses sum = 44 + 5 × 2 = 54। बच्चा 3 साल जोड़ें: family sum = 57। 3 लोगों का avg = 57/3 = 19 साल।', 'समय बीतने पर हर मौजूद सदस्य की age उतनी बढ़ती है, sum = (सदस्य × elapsed) बढ़ती है। नया सदस्य जुड़ने पर उसकी age sum में जुड़ती है पर count भी बढ़ता है — average dilute होती है।', 'HARD', array['average','age','family-changes','cbt1-full-mock','mathematics']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', '19 years', '19 साल', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', '27 years', '27 साल', false, 'Computed only the spouses'' present average (22 + 5 = 27) and ignored the child. Family of 3 includes child; recompute avg = (54 + 3)/3 = 19.', 'केवल spouses की present average (22 + 5 = 27) ली, बच्चा छोड़ दिया। Family of 3 में बच्चा शामिल: avg = 57/3 = 19।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', '21 years', '21 साल', false, 'Took elapsed time as 5 + 3 = 8 years (added child age to elapsed): spouses now 30 each, family sum 30+30+3 = 63, avg = 21. Question states only 5 years passed since marriage.', 'Elapsed time को 5 + 3 = 8 साल मान लिया: spouses 30 each, family sum 63, avg 21। शादी के 5 साल बाद ही present है।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', '17 years', '17 साल', false, 'Added only one +5 to spouses'' sum (forgot the second spouse): 44 + 5 = 49 + 3 = 52, /3 = 17.33 → 17. Both spouses age, so add 5 × 2 = 10.', 'केवल एक spouse पर +5 लगाया (दूसरा भूल गए): 44 + 5 = 49 + 3 = 52, /3 = 17.33 → 17। दोनों spouses age होते हैं, +10 लगता है।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 25, 'The average age of A and B is 35 years. The average of A, B, and C is 30 years. Find C''s age.', 'A और B की average age 35 साल है। A, B और C की average age 30 साल है। C की age क्या है?', 'A + B = 2 × 35 = 70. A + B + C = 3 × 30 = 90. C = 90 − 70 = 20.', 'When you have two overlapping averages where the larger group includes the smaller one plus one more element, isolate the new element by subtracting the smaller-group sum from the larger-group sum.', 'A + B = 2 × 35 = 70। A + B + C = 3 × 30 = 90। C = 90 − 70 = 20।', 'जब छोटा group बड़े का subset हो (एक element अधिक), तो नए element को बड़े group sum − छोटे group sum से निकालें।', 'MEDIUM', array['average','age','missing-element','cbt1-full-mock','mathematics']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', '20 years', '20 साल', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', '30 years', '30 साल', false, 'Reported the three-person average (30) as C''s age. The trio average comes from BOTH A+B and C; isolate C via sums.', 'तीनों का average (30) C की age कह दिया। Average दोनों A+B और C से बनती है — C को sums से isolate करें।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', '35 years', '35 साल', false, 'Reported the A+B average (35) as C''s age. Average of A and B doesn''t equal a third person''s age.', 'A+B average (35) को C की age कह दिया। A और B की average किसी तीसरे की age नहीं होती।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', '25 years', '25 साल', false, 'Used midpoint of 30 and 35 → 32.5, then trimmed to 25. Correct: C = 3 × 30 − 2 × 35 = 90 − 70 = 20.', '30 और 35 के बीच का midpoint लगाकर 25 कर दिया। सही: C = 3 × 30 − 2 × 35 = 90 − 70 = 20।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 26, 'The average of 9 numbers is 12. If a 10th number is added and the new average is the same, what is the 10th number?', '9 संख्याओं का average 12 है। 10वीं संख्या जोड़ने पर भी average वही रहता है। 10वीं संख्या क्या है?', 'For the average to stay at 12 after adding a 10th number, that number must itself be 12 (otherwise the average shifts).', 'Adding a number equal to the existing average leaves the average unchanged. Adding above pulls it up; adding below pulls it down. The ''fulcrum'' of the average is its own value.', 'Average 12 same रहने के लिए 10वीं संख्या भी 12 होनी चाहिए (अन्यथा average shift हो जाती)।', 'Existing average के बराबर value जोड़ने पर average नहीं बदलता। ऊपर जोड़ने पर ऊपर, नीचे जोड़ने पर नीचे जाती है। Average का ''fulcrum'' खुद वही value है।', 'EASY', array['average','addition','average-stable','cbt1-full-mock','mathematics']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', '12', '12', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', '0', '0', false, 'Reasoned ''no shift means add nothing''. But ''no shift'' means the new value equals the existing average, which is 12 (not 0).', '''Shift = 0 ⇒ add 0'' सोच लिया। पर ''no shift'' का मतलब नया value = existing average = 12, 0 नहीं।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', '10', '10', false, 'Reported the new count (10) as the answer. Count is not value.', 'नई count (10) को answer दे दिया। Count value नहीं है।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', '120', '120', false, 'Reported the total sum (10 × 12 = 120) as the 10th number. Sum is the cumulative total, not a single value.', 'Total sum (10 × 12 = 120) को 10वीं संख्या कह दिया। Sum cumulative है, single value नहीं।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 27, 'The average of 50 numbers is 30. Each number is increased by 5%. Find the new average.', '50 संख्याओं का average 30 है। हर संख्या 5% बढ़ा दी जाए तो नया average क्या होगा?', 'Multiplying every value by 1.05 multiplies the average by 1.05: new avg = 30 × 1.05 = 31.5.', 'Average is linear: a uniform percent increase on every value gives the same percent increase on the average. Equivalently, new avg = old avg × (1 + p/100).', 'हर value × 1.05 ⇒ average भी × 1.05: नई avg = 30 × 1.05 = 31.5।', 'Average linear: हर value पर uniform % increase से average पर भी वही % increase। नई avg = पुरानी × (1 + p/100)।', 'MEDIUM', array['average','uniform-percentage','scale','cbt1-full-mock','mathematics']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', '31.5', '31.5', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', '35', '35', false, 'Added 5 to the average: 30 + 5 = 35. The shift is 5% of average = 1.5, not flat 5.', 'Average में 5 जोड़ दिया: 30 + 5 = 35। Shift average का 5% = 1.5, flat 5 नहीं।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', '30', '30', false, 'Kept the average unchanged. Multiplying every value by 1.05 raises the average by 5%, not by 0.', 'Average वही रखी। हर value × 1.05 ⇒ average भी 5% बढ़ती है।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', '32.5', '32.5', false, 'Computed 1.05 × 30 ≈ 31.5 but adjusted up to 32.5 thinking ''average grows faster than 5%''. It grows by exactly 5%.', '1.05 × 30 = 31.5 निकाला पर 32.5 कर दिया (''average 5% से ज़्यादा बढ़ती है'' सोचकर)। Average exactly 5% बढ़ती है।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 28, 'The average of three numbers a, b, c is 20. The average of a, b, c, d is 24. Find the value of d.', 'तीन संख्याओं a, b, c का average 20 है। a, b, c, d का average 24 है। d का मान क्या है?', 'Sum a+b+c = 3 × 20 = 60. Sum a+b+c+d = 4 × 24 = 96. d = 96 − 60 = 36. Shortcut: d = new_avg + count_old × Δ = 24 + 3 × 4 = 36.', 'Adding a single element shifts the sum by exactly that element''s value. The shortcut d = new_avg + count_old × Δ comes from the fact that d must be at the new average AND raise everyone else by Δ — so d = new_avg + (people lifted) × Δ.', 'Sum a+b+c = 60। Sum a+b+c+d = 96। d = 96 − 60 = 36।', 'एक element जोड़ने पर sum उसकी value जितना बदलता है। Shortcut: d = new_avg + count_old × Δ।', 'EASY', array['average','addition','missing-element','cbt1-full-mock','mathematics']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', '36', '36', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', '24', '24', false, 'Reported the new four-element average (24) as d. d = 4 × 24 − 3 × 20 = 96 − 60 = 36.', 'चार-element average (24) को d कह दिया। सही: d = 4 × 24 − 3 × 20 = 96 − 60 = 36।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', '4', '4', false, 'Reported the average shift (24 − 20 = 4) as d. The shift moves the group; d is much larger.', 'Average shift (24 − 20 = 4) को d कह दिया। Shift group पर लगता है; d बहुत बड़ा है।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', '44', '44', false, 'Used d = new_avg + count_old × Δ = 24 + 3 × 4 = 36 in shortcut, but stretched to 44 by an arithmetic slip (added 4 once more).', 'Shortcut d = new_avg + count_old × Δ = 24 + 3 × 4 = 36 सही, पर 4 एक बार और जोड़कर 44 कर दिया।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 29, 'The average monthly income of A, B, C is ₹4,000. The average of A and C is ₹3,500, and that of B and C is ₹4,500. Find C''s income.', 'A, B, C की monthly income का average ₹4,000 है। A और C का ₹3,500, और B और C का ₹4,500 है। C की income क्या है?', 'A + B + C = 3 × 4000 = 12000. A + C = 2 × 3500 = 7000. B + C = 2 × 4500 = 9000. Adding the two pairs: A + B + 2C = 16000. Subtract A+B+C = 12000: C = 16000 − 12000 = 4000.', 'Three sums (full triple, pair-AC, pair-BC) form a linear system in three unknowns. Adding the two pairs counts C twice; subtracting the full triple isolates C. Pair-overlap on a single element is the canonical setup for such problems.', 'A + B + C = 12000, A + C = 7000, B + C = 9000। दोनों pairs जोड़ें: A + B + 2C = 16000। A + B + C = 12000 घटाएँ: C = 4000।', 'तीन sums (पूरी triple, pair-AC, pair-BC) तीन-variable linear system बनाते हैं। दोनों pairs जोड़ने पर C double हो जाता है; full triple घटाने से C alone निकलता है।', 'HARD', array['average','three-equations','system','cbt1-full-mock','mathematics']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', '₹4,000', '₹4,000', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', '₹3,500', '₹3,500', false, 'Reported the A+C pair average (3500) as C alone. C is shared in both pair averages but isn''t equal to either pair average.', 'A+C pair average (3500) को C अकेले कह दिया। C दोनों pair averages में shared है पर किसी एक के बराबर नहीं।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', '₹4,500', '₹4,500', false, 'Reported the B+C pair average (4500) as C alone. Same mistake on the other pair.', 'B+C pair average (4500) को C अकेले कह दिया।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', '₹2,500', '₹2,500', false, 'Used 7000 + 9000 − 12000 = 4000 correctly but slipped to 2500 by treating one of the pair averages as 5000.', 'Sum 7000 + 9000 − 12000 = 4000 सही method पर pair को 5000 पढ़कर 2500 निकाला।');
insert into public.test_sections (test_id, title_en, title_hi, question_count, display_order, subject_hint) values (v_t, 'General Intelligence & Reasoning', 'General Intelligence & Reasoning', 30, 3, 'reason') returning id into v_s;
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 0, 'In a code, each letter is shifted 1 places forward. How is STATION coded?', 'एक code में हर letter 1 places आगे shift होता है। STATION को कैसे code करेंगे?', 'Move every letter of STATION forward by 1: STATION becomes TUBUJPO. Therefore, answer = TUBUJPO.', 'Letter-shift coding uses alphabet positions. Apply the same displacement to each character and wrap after Z if needed. Final answer is TUBUJPO.', 'STATION के हर letter को 1 आगे करें: STATION का code TUBUJPO होगा। अतः answer = TUBUJPO।', 'Letter-shift coding में alphabet positions use होते हैं। हर character पर same displacement लगाएँ। Final answer TUBUJPO है।', 'MEDIUM', array['coding-decoding','letter-shift','cbt1-full-mock','reasoning']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', 'RSZSHNM', 'RSZSHNM', false, 'Shifted 1 places backward instead of forward.', '1 places forward की जगह backward shift किया।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', 'NOITATS', 'NOITATS', false, 'Reversed the word but did not apply the letter shift.', 'Word reverse किया पर letter shift apply नहीं किया।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', 'TUBUJPO', 'TUBUJPO', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', 'OPJUBUT', 'OPJUBUT', false, 'Applied the shift but also reversed the result, which the rule never says.', 'Shift apply करके result reverse भी कर दिया, जबकि rule में reverse नहीं है।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 1, 'In a code, each letter is shifted 2 places forward. How is WAGON coded?', 'एक code में हर letter 2 places आगे shift होता है। WAGON को कैसे code करेंगे?', 'Move every letter of WAGON forward by 2: WAGON becomes YCIQP. Therefore, answer = YCIQP.', 'Letter-shift coding uses alphabet positions. Apply the same displacement to each character and wrap after Z if needed. Final answer is YCIQP.', 'WAGON के हर letter को 2 आगे करें: WAGON का code YCIQP होगा। अतः answer = YCIQP।', 'Letter-shift coding में alphabet positions use होते हैं। हर character पर same displacement लगाएँ। Final answer YCIQP है।', 'MEDIUM', array['coding-decoding','letter-shift','cbt1-full-mock','reasoning']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', 'UYEML', 'UYEML', false, 'Shifted 2 places backward instead of forward.', '2 places forward की जगह backward shift किया।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', 'NOGAW', 'NOGAW', false, 'Reversed the word but did not apply the letter shift.', 'Word reverse किया पर letter shift apply नहीं किया।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', 'PQICY', 'PQICY', false, 'Applied the shift but also reversed the result, which the rule never says.', 'Shift apply करके result reverse भी कर दिया, जबकि rule में reverse नहीं है।');
