insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 2, 'In a code, each letter is shifted 3 places forward. How is BRIDGE coded?', 'एक code में हर letter 3 places आगे shift होता है। BRIDGE को कैसे code करेंगे?', 'Move every letter of BRIDGE forward by 3: BRIDGE becomes EULGJH. Therefore, answer = EULGJH.', 'Letter-shift coding uses alphabet positions. Apply the same displacement to each character and wrap after Z if needed. Final answer is EULGJH.', 'BRIDGE के हर letter को 3 आगे करें: BRIDGE का code EULGJH होगा। अतः answer = EULGJH।', 'Letter-shift coding में alphabet positions use होते हैं। हर character पर same displacement लगाएँ। Final answer EULGJH है।', 'MEDIUM', array['coding-decoding','letter-shift','cbt1-full-mock','reasoning']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
