insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', 'EGDIRB', 'EGDIRB', false, 'Reversed the word but did not apply the letter shift.', 'Word reverse किया पर letter shift apply नहीं किया।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', 'HJGLUE', 'HJGLUE', false, 'Applied the shift but also reversed the result, which the rule never says.', 'Shift apply करके result reverse भी कर दिया, जबकि rule में reverse नहीं है।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 3, 'If words are coded by reversing their letters, how is RAIL coded?', 'यदि words को letters reverse करके code किया जाता है, तो RAIL का code क्या होगा?', 'Reverse the order of letters in RAIL: LIAR. Therefore, answer = LIAR.', 'In reverse coding, letter identities stay unchanged; only their positions are mirrored from end to start. Final answer is LIAR.', 'RAIL के letters का order reverse करें: LIAR। अतः answer = LIAR।', 'Reverse coding में letters वही रहते हैं; सिर्फ positions end से start तक mirror होती हैं। Final answer LIAR है।', 'MEDIUM', array['coding-decoding','reverse-coding','cbt1-full-mock','reasoning']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', 'RAIL', 'RAIL', false, 'Left the word unchanged and missed the reverse rule.', 'Word unchanged छोड़ दिया और reverse rule miss कर दिया।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', 'LIAR', 'LIAR', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', 'SBJM', 'SBJM', false, 'Shifted letters by +1 instead of reversing their order.', 'Order reverse करने की जगह letters +1 shift कर दिए।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', 'IARL', 'IARL', false, 'Reversed first but then rotated one letter, which is not part of the rule.', 'पहले reverse किया फिर one-letter rotation कर दिया, rule में rotation नहीं है।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 4, 'If words are coded by reversing their letters, how is TRAIN coded?', 'यदि words को letters reverse करके code किया जाता है, तो TRAIN का code क्या होगा?', 'Reverse the order of letters in TRAIN: NIART. Therefore, answer = NIART.', 'In reverse coding, letter identities stay unchanged; only their positions are mirrored from end to start. Final answer is NIART.', 'TRAIN के letters का order reverse करें: NIART। अतः answer = NIART।', 'Reverse coding में letters वही रहते हैं; सिर्फ positions end से start तक mirror होती हैं। Final answer NIART है।', 'MEDIUM', array['coding-decoding','reverse-coding','cbt1-full-mock','reasoning']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
